mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, a.* FROM ( SELECT b.BANNER_ID AS bannerId, b.FK_MEMBERID AS fkMemberId, b.TITLE AS title, b.IMAGE_FILE_ID AS imageFileId, img.FILE_URL AS imageFileUrl, b.START_AT AS startAt, b.END_AT AS endAt, b.STATUS AS status, b.REJECT_REASON AS rejectReason, c.COMPANY_NAME AS companyName, pt.created_at AS createdAt FROM TBL_BANNER b LEFT JOIN TBL_COMPANY c ON b.FK_MEMBERID = c.FK_MEMBERID LEFT JOIN TBL_IMAGE_FILE img ON img.FILE_ID = b.IMAGE_FILE_ID LEFT JOIN ( SELECT FK_BANNER_ID, MIN(CREATED_AT) AS created_at FROM TBL_POINT_TRANSACTION GROUP BY FK_BANNER_ID ) pt ON pt.FK_BANNER_ID = b.BANNER_ID WHERE 1=1
AND b.STATUS = #{status}
AND b.STATUS != '마감' AND b.STATUS != '삭제됨'
ORDER BY b.BANNER_ID DESC ) a WHERE ROWNUM <= #{offset} + #{limit} ) WHERE rn > #{offset}

SELECT COUNT(*) FROM TBL_BANNER where 1=1
AND STATUS = #{status}
AND STATUS != '마감' AND STATUS != '삭제됨'

mapper.update:
UPDATE TBL_BANNER
SET STATUS = '반려', REJECT_REASON = #{rejectReason}
WHERE BANNER_ID = #{bannerId}

mapper.select:
SELECT POINT_WALLET_ID
FROM TBL_POINT_WALLET
WHERE FK_MEMBERID = #{fkMemberId}

mapper.update:
UPDATE TBL_POINT_WALLET
SET AVAILABLE_BALANCE = AVAILABLE_BALANCE + #{amount}
WHERE POINT_WALLET_ID = #{walletId}
